import { duration } from "moment";
import { useEffect } from "react";
import { calculateInstallments } from "./utils";

const plansData = [
    {
        id: 'plan-1',
        label: '24x',
        duration: '24'
    },
    {
        id: 'plan-2',
        label: '12x',
        duration: '12'
    },
    {
        id: 'plan-3',
        label: '6x',
        duration: '6'
    },
    {
        id: 'plan-4',
        label: '3x',
        duration: '3'
    }
]
const totAmnt = 24000
// 7:33 useData till write insta, store

export async function getInstallments(total, duration) {
    return new Promise((resolve) => {
        const installments = calculateInstallments(total, duration)
        setTimeout(() => {
            return resolve(installments)
        }, 500)
    })
}

export async function getTotalAmount() {
    return new Promise((resolve) => {
        setTimeout(() => {
            return resolve(totAmnt)
        }, 500)
    })
}

export async function getPlansData() {
    return new Promise((resolve) => {
        setTimeout(() => {
            return resolve(plansData)
        }, 500)
    })
}

function useData({ fn }) {
    const [resp, setResp] = useState({
        loading: false,
        data: null,
        error: null,
    })
    async function fetchData(fn) {
        setResp((prev) => {
            return {
                ...prev,
                loading: false,
            }
        })
        try {
            const result = await fn()
            if (result) {
                setResp((prev) => {
                    return {
                        ...prev,
                        data: result,
                    }
                })
            }
        }
        catch (err) {
            setResp((prev) => {
                return {
                    ...prev,
                    error: {
                        message: 'Something went worng'
                    },
                }
            })
        } finally {
            setResp((prev) => {
                return {
                    ...prev,
                    loading: false,
                }
            })
        }
    }
    useEffect(() => {
        fetchData(fn)
    }, [fn])
    return resp
}

export default useData
